      Formatter::SubstitutionFormatStringUtils::createJsonFormatter(proto_config.record(), false,
                                                                    commands);
  FluentdFormatterPtr fluentd_formatter =
      std::make_unique<FluentdFormatterImpl>(std::move(json_formatter));

