    17→namespace Envoy {
    18→namespace Extensions {
    19→namespace AccessLoggers {
    20→namespace OpenTelemetry {
    21→
    22→// Singleton registration via macro defined in envoy/singleton/manager.h
    23→SINGLETON_MANAGER_REGISTRATION(open_telemetry_access_logger_cache);
    24→SINGLETON_MANAGER_REGISTRATION(open_telemetry_http_access_logger_cache);
    25→
    26→std::shared_ptr<GrpcAccessLoggerCacheImpl>
    27→getGrpcAccessLoggerCacheSingleton(Server::Configuration::CommonFactoryContext& context) {
    28→  return context.singletonManager().getTyped<GrpcAccessLoggerCacheImpl>(
    29→      SINGLETON_MANAGER_REGISTERED_NAME(open_telemetry_access_logger_cache), [&context] {
    30→        return std::make_shared<GrpcAccessLoggerCacheImpl>(
    31→            context.clusterManager().grpcAsyncClientManager(), context.serverScope(),
    32→            context.threadLocal(), context.localInfo());
    33→      });
    34→}
    35→
    36→HttpAccessLoggerCacheSharedPtr
    37→getHttpAccessLoggerCacheSingleton(Server::Configuration::CommonFactoryContext& context) {
    38→  return context.singletonManager().getTyped<HttpAccessLoggerCacheImpl>(
    39→      SINGLETON_MANAGER_REGISTERED_NAME(open_telemetry_http_access_logger_cache), [&context] {
    40→        return std::make_shared<HttpAccessLoggerCacheImpl>(
    41→            context.clusterManager(), context.serverScope(), context.threadLocal(),
    42→            context.localInfo());
    43→      });
    44→}
    45→
    46→::Envoy::AccessLog::InstanceSharedPtr AccessLogFactory::createAccessLogInstance(
    47→    const Protobuf::Message& config, ::Envoy::AccessLog::FilterPtr&& filter,
    48→    Server::Configuration::GenericFactoryContext& context,
    49→    std::vector<Formatter::CommandParserPtr>&& command_parsers) {
    50→  validateProtoDescriptors();
    51→
    52→  const auto& proto_config = MessageUtil::downcastAndValidate<
    53→      const envoy::extensions::access_loggers::open_telemetry::v3::OpenTelemetryAccessLogConfig&>(
    54→      config, context.messageValidationVisitor());
    55→
    56→  // Validate transport configuration: exactly one transport must be specified.
    57→  const bool has_grpc_service = proto_config.has_grpc_service();
    58→  const bool has_http_service = proto_config.has_http_service();
    59→  const bool has_common_config_grpc =
    60→      proto_config.has_common_config() && proto_config.common_config().has_grpc_service();
    61→
    62→  const int transport_count =
    63→      (has_grpc_service ? 1 : 0) + (has_http_service ? 1 : 0) + (has_common_config_grpc ? 1 : 0);
    64→
    65→  if (transport_count == 0) {
    66→    throw EnvoyException(
    67→        "OpenTelemetry access logger requires one of: grpc_service, http_service, or "
    68→        "common_config.grpc_service to be configured.");
    69→  }
